package com.chaobo.scm.supplier.infrastructure.persistence.qualification;
import org.apache.ibatis.annotations.*;import java.time.*;import java.util.*;
@Mapper public interface SupplierQualificationMapper {record Row(long id,long supplierId,String type,String number,LocalDate from,LocalDate to,String attachment,int status,String remark,int version){}@Select("SELECT qualification_id id,supplier_id supplierId,qualification_type type,qualification_no number,valid_from `from`,valid_to `to`,attachment_url attachment,qualification_status status,review_remark remark,version FROM sup_supplier_qualification WHERE qualification_id=#{id} AND deleted=0")Row find(long id);@Insert("INSERT INTO sup_supplier_qualification(qualification_id,supplier_id,qualification_type,qualification_no,valid_from,valid_to,attachment_url,qualification_status,review_remark,created_by,updated_by,version,deleted) VALUES(#{r.id},#{r.supplierId},#{r.type},#{r.number},#{r.from},#{r.to},#{r.attachment},#{r.status},#{r.remark},#{operator},#{operator},#{r.version},0)")void insert(@Param("r")Row r,@Param("operator")long operator);@Update("UPDATE sup_supplier_qualification SET qualification_status=#{r.status},review_remark=#{r.remark},updated_by=#{operator},version=#{r.version} WHERE qualification_id=#{r.id} AND version=#{expected} AND deleted=0")int update(@Param("r")Row r,@Param("expected")int expected,@Param("operator")long operator);@Select("SELECT COUNT(*) FROM sup_supplier_qualification WHERE supplier_id=#{supplierId} AND qualification_status=2 AND valid_to>=CURDATE() AND deleted=0")boolean hasValid(long supplierId);@Select("<script>SELECT qualification_type FROM sup_qualification_requirement WHERE status=1 AND mandatory=1 AND (category_id IS NULL OR category_id=#{categoryId}) ORDER BY category_id IS NOT NULL DESC</script>")List<String> requiredTypes(@Param("categoryId")Long categoryId);@Select("<script>SELECT COUNT(DISTINCT qualification_type) FROM sup_supplier_qualification WHERE supplier_id=#{supplierId} AND qualification_status=2 AND valid_to>=CURDATE() AND deleted=0 AND qualification_type IN <foreach collection='types' item='type' open='(' separator=',' close=')'>#{type}</foreach></script>")long validRequiredCount(@Param("supplierId")long supplierId,@Param("types")List<String> types);@Select("<script>SELECT COUNT(*) FROM sup_supplier_qualification WHERE deleted=0 <if test='supplierId != null'>AND supplier_id=#{supplierId}</if><if test='status != null'>AND qualification_status=#{status}</if></script>")long count(@Param("supplierId")Long supplierId,@Param("status")Integer status);@Select("<script>SELECT qualification_id id,supplier_id supplierId,qualification_type type,qualification_no number,valid_from `from`,valid_to `to`,attachment_url attachment,qualification_status status,review_remark remark,version FROM sup_supplier_qualification WHERE deleted=0 <if test='supplierId != null'>AND supplier_id=#{supplierId}</if><if test='status != null'>AND qualification_status=#{status}</if> ORDER BY valid_to ASC LIMIT #{offset},#{size}</script>")List<Row> page(@Param("supplierId")Long supplierId,@Param("status")Integer status,@Param("offset")int offset,@Param("size")int size);@Select("SELECT qualification_id FROM sup_supplier_qualification WHERE qualification_status=2 AND valid_to<CURDATE() AND deleted=0")List<Long> expiredIds();}
